def is_palindrome(s):
    start_index = 0
    end_index = len(s) - 1

    while start_index < end_index:
        if s[start_index] != s[end_index]:
            return False
        start_index += 1
        end_index -= 1

    return True

def is_palindrome(s):
    cleaned = s.lower().replace(" ", "")
    return cleaned == cleaned[::-1]

def is_palindrome(s):
    clean_s = "".join(c.lower() for c in s if c.isalnum())
    return clean_s == clean_s[::-1]
